import React, { Component } from 'react';
import pixelPerfect from '../images/pixel-perfect.png';
import responsive from '../images/responsive-web-design-2.png';
import workflow from '../images/work-flow.png';
import teamWork from '../images/team-work.png';

export default class Skill extends Component {
    render() {
        return (
            <div className="container skill"> 
                
                <span className="skill-wrap">
                    <div className="skill-image">
                        <img src={pixelPerfect}  alt="skill-image" />                        
                    </div>
                    <div>
                        <h3>Pixel Perfect</h3>
                        <p>My designs are pixel perfect, with strong emphasis on user empathy.</p>
                    </div>
                </span>
                <span className="skill-wrap">
                    <div className="skill-image">
                        <img src={teamWork}  alt="skill-image" />                        
                    </div>
                    <div>
                        <h3>Team Player</h3>
                        <p>I am a team player with a long experiencne of working with both in-house and remote teams.</p>
                    </div>
                </span>
                <span className="skill-wrap">
                    <div className="skill-image">
                        <img src={responsive}  alt="skill-image" />                        
                    </div>
                    <div>
                    <h3>Responsive Design</h3>
                        <p>All the website apps I build are fully mobile responsive across all devices.</p>
                    </div>
                </span>
                <span className="skill-wrap">
                    <div className="skill-image">
                        <img src={workflow}  alt="skill-image" />                        
                    </div>
                    <div>
                        <h3>Collaboration</h3>
                        <p>I boast of years of experience with a wide range of collaboration tools including Git, Invision, Hotgloo, Slack, Sketch, </p>
                    </div>
                </span>
            </div>
        )
    }
}
