import React, { Component } from 'react';
import chrome from '../images/chrome.png';
import vsCode from '../images/vs-code.png';
import phpmyadmin from '../images/phpmyadmin.png';
import git from '../images/git.png';
import postman from '../images/postman.png';
import invision from '../images/invision.png';

export default class Tools extends Component {
    render() {
        return (
            <div className="container ">
                <h1 className="center-text">Tools</h1> <hr />
                <div className="tools">
                    <span>
                        <img src={chrome}  alt="restrr-app" /> 
                    </span>
                    <span>
                        <img src={vsCode}  alt="restrr-app" /> 
                    </span>
                    <span>
                        <img src={phpmyadmin}  alt="restrr-app" /> 
                    </span>
                    <span>
                        <img src={git}  alt="restrr-app" /> 
                    </span>
                    <span>
                        <img src={postman}  alt="restrr-app" /> 
                    </span>
                    <span>
                        <img src={invision}  alt="restrr-app" /> 
                    </span>
                </div>
            </div>
        )
    }
}
